  "description": "Invalidating the session emits a cleared cookie (empty value, not http-only) so the client drops it.",
  "cases": [
    {
      "input": {
        "op": "http",
        "storage": {
          "type": "sealed"
        },
        "scenario": "invalidate",
        "incoming": {
          "data": {
            "a": 1,
            "b": 2
          }
        }
      },
      "expected_output": "status=200\nloaded.new=false\nloaded.empty=false\nloaded.contents={\"a\": 1, \"b\": 2}\nset_cookie=present\ncookie.cleared=true\ncookie.httponly=false\ncookie.path=/\ncookie.domain=127.0.0.1\ncookie.max_age=0\ncookie.expires=Thu, 01 Jan 1970 00:00:00 GMT\n"
    }
  ]
}

Here are the public test cases for feature6_6_session_fixation:
{
  "description": "After a session is invalidated, replaying a previously captured cookie cannot resurrect the old session: a subsequent login issues a different cookie value, and the logout response clears the cookie.",
  "cases": [
    {
      "input": {
        "op": "fixation",
        "storage": {
          "type": "sealed"
        }
      },
      "expected_output": "login_cookie=present\nlogout_cookie_cleared=true\nreplay_cookie_differs=true\n"
    }
  ]
}

Here are the public test cases for feature6_7_corrupted_cookie:
{
  "description": "An incoming cookie whose value is not a valid authenticated token is rejected and the handler receives a fresh empty session.",
  "cases": [
    {
      "input": {
        "op": "http",
        "storage": {
          "type": "sealed"
        },
        "scenario": "read",
        "incoming": {
          "mode": "raw",
          "raw": "bad key"
        }
      },
      "expected_output": "status=200\nloaded.new=true\nloaded.empty=true\nloaded.contents={}\nset_cookie=absent\n"
    }
  ]
}

Here are the public test cases for feature6_8_foreign_cookie:
{
  "description": "An incoming cookie produced under a different key cannot be authenticated and the handler receives a fresh empty session.",
  "cases": [
    {
      "input": {
        "op": "http",
        "storage": {
          "type": "sealed"
        },
        "scenario": "read",
        "incoming": {
          "data": {
            "a": 1,
            "b": 12
          },
          "mode": "wrong_key"
        }
      },
      "expected_output": "status=200\nloaded.new=true\nloaded.empty=true\nloaded.contents={}\nset_cookie=absent\n"
    }
  ]
}

